let baseEnemy = { hp: 100, speed: 50, type: "Grunt" };

// We spawn a Boss by cloning all the Grunt stats, but upgrading the HP!
let bossEnemy = { ...baseEnemy, hp: 5000, type: "Boss" };

console.log("Base Enemy HP: ", baseEnemy.hp);
console.log("Boss Enemy HP: ", bossEnemy.hp);

